  1	import * as _ from "lodash-es";
  2	import * as React from "react";
  3	import * as classNames from "classnames";
  4	import {
  5	  Alert,
  6	  Button,
  7	  Spinner,
  8	  PageSection,
  9	  Title,
 10	} from "@patternfly/react-core";
 11	import { Trans } from "react-i18next";
 12	
 13	import { IncompleteDataError, TimeoutError } from "./error/http-error";
 14	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 15	import { get, isString, isEmpty } from "lodash-es";
 16	
 17	export const Box: React.FC<BoxProps> = ({ children, className }) => (
 18	  <div className={classNames("cos-status-box", className)}>{children}</div>
 19	);
 20	
 21	export const LoadError: React.FC<LoadErrorProps> = ({
 22	  label,
 23	  className,
 24	  message,
 25	  canRetry = true,
 26	}) => {
 27	  const { t } = useNodeHealthCheckTranslation();
 28	  return (
 29	    <Box className={className}>
 30	      <div className="pf-u-text-align-center cos-error-title">
 31	        {isString(message)
 32	          ? t("Error Loading {{label}}: {{message}}", {
 33	              label,
 34	              message,
 35	            })
 36	          : t("Error Loading {{label}}", { label })}
 37	      </div>
 38	      {canRetry && (
 39	        <div className="pf-u-text-align-center">
 40	          <Trans ns="plugin__node-remediation-console-plugin">
 41	            Please{" "}
 42	            <Button
 43	              type="button"
 44	              onClick={window.location.reload.bind(window.location)}
 45	              variant="link"
 46	              isInline
 47	            >
 48	              try again
 49	            </Button>
 50	            .
 51	          </Trans>
 52	        </div>
 53	      )}
 54	    </Box>
 55	  );
 56	};
 57	LoadError.displayName = "LoadError";
 58	
 59	export const Loading: React.FC<LoadingProps> = ({ className }) => (
 60	  <Spinner size="lg" className={className} data-test="loading-indicator" />
 61	);
 62	Loading.displayName = "Loading";
 63	
 64	export const LoadingInline: React.FC<{}> = () => <Spinner size="md" />;
 65	LoadingInline.displayName = "LoadingInline";
 66	
 67	export const LoadingBox: React.FC<LoadingBoxProps> = ({
 68	  className,
 69	  message,
 70	}) => (
 71	  <Box className={classNames("cos-status-box--loading", className)}>
 72	    <Loading />
 73	    {message && (
 74	      <div className="cos-status-box__loading-message">{message}</div>
 75	    )}
 76	  </Box>
 77	);
 78	LoadingBox.displayName = "LoadingBox";
 79	
 80	export const EmptyBox: React.FC<EmptyBoxProps> = ({ label }) => {
 81	  const { t } = useNodeHealthCheckTranslation();
 82	  return (
 83	    <Box>
 84	      <div data-test="empty-message" className="pf-u-text-align-center">
 85	        {label
 86	          ? t("No {{label}} found", {
 87	              label,
 88	            })
 89	          : t("Not found")}
 90	      </div>
 91	    </Box>
 92	  );
 93	};
 94	EmptyBox.displayName = "EmptyBox";
 95	
 96	export const MsgBox: React.FC<MsgBoxProps> = ({
 97	  title,
 98	  detail,
 99	  className = "",
100	}) => (
101	  <Box className={className}>
102	    {title && (
103	      <div className="cos-status-box__title" data-test="msg-box-title">
104	        {title}
105	      </div>
106	    )}
107	    {detail && (
108	      <div
109	        className="pf-u-text-align-center cos-status-box__detail"
110	        data-test="msg-box-detail"
111	      >
112	        {detail}
113	      </div>
114	    )}
115	  </Box>
116	);
117	MsgBox.displayName = "MsgBox";
118	
119	export const AccessDenied: React.FC<AccessDeniedProps> = ({ message }) => {
120	  const { t } = useNodeHealthCheckTranslation();
121	  return (
122	    <div>
123	      <Box className="pf-u-text-align-center">
124	        <img className="cos-status-box__access-denied-icon" />
125	        <MsgBox
126	          title={t("Restricted Access")}
127	          detail={t(
128	            "You don't have access to this section due to cluster policy."
129	          )}
130	        />
131	      </Box>
132	      {isString(message) && (
133	        <Alert isInline variant="danger" title={t("Error details")}>
134	          {message}
135	        </Alert>
136	      )}
137	    </div>
138	  );
139	};
140	AccessDenied.displayName = "AccessDenied";
141	
142	const Data: React.FC<DataProps> = ({
143	  NoDataEmptyMsg,
144	  EmptyMsg,
145	  label,
146	  data,
147	  unfilteredData,
148	  children,
149	}) => {
150	  if (NoDataEmptyMsg && isEmpty(unfilteredData)) {
151	    return (
152	      <div className="loading-box loading-box__loaded">
153	        {NoDataEmptyMsg ? <NoDataEmptyMsg /> : <EmptyBox label={label} />}
154	      </div>
155	    );
156	  }
157	
158	  if (!data || isEmpty(data)) {
159	    return (
160	      <div className="loading-box loading-box__loaded">
161	        {EmptyMsg ? <EmptyMsg /> : <EmptyBox label={label} />}
162	      </div>
163	    );
164	  }
165	  return (
166	    <div
167	      className="loading-box loading-box__loaded"
168	      data-test="loading-box__loaded"
169	    >
170	      {children}
171	    </div>
172	  );
173	};
174	Data.displayName = "Data";
175	
176	export const StatusBox: React.FC<StatusBoxProps> = (props) => {
177	  const { loadError, loaded, skeleton, data, ...dataProps } = props;
178	  const { t } = useNodeHealthCheckTranslation();
179	
180	  if (loadError) {
181	    const status = get(loadError, "response.status");
182	    if (status === 404) {
183	      return (
184	        <PageSection variant="light">
185	          <Title headingLevel="h1">{t("404: Not Found")}</Title>
186	        </PageSection>
187	      );
188	    }
189	    if (status === 403) {
190	      return <AccessDenied message={loadError.message} />;
191	    }
192	
193	    if (loadError instanceof IncompleteDataError && !isEmpty(data)) {
194	      return (
195	        <Data data={data} {...dataProps}>
196	          <Alert
197	            variant="info"
198	            isInline
199	            title={t(
200	              "{{labels}} content is not available in the catalog at this time due to loading failures.",
201	              {
202	                labels: loadError.labels.join(","),
203	              }
204	            )}
205	          />
206	          {props.children}
207	        </Data>
208	      );
209	    }
210	
211	    if (loaded && loadError instanceof TimeoutError) {
212	      return (
213	        <Data data={data} {...dataProps}>
214	          <div className="pf-v5-u-color-200">
215	            {t("Timed out fetching new data. The data below is stale.")}
216	          </div>
217	          {props.children}
218	        </Data>
219	      );
220	    }
221	
222	    return (
223	      <LoadError
224	        message={loadError.message}
225	        label={props.label}
226	        className="loading-box loading-box__errored"
227	      />
228	    );
229	  }
230	
231	  if (!loaded) {
232	    return skeleton ? (
233	      <>{skeleton}</>
234	    ) : (
235	      <LoadingBox className="loading-box loading-box__loading" />
236	    );
237	  }
238	  return <Data data={data} {...dataProps} />;
239	};
240	StatusBox.displayName = "StatusBox";
241	
242	type BoxProps = {
243	  children: React.ReactNode;
244	  className?: string;
245	};
246	
247	type LoadErrorProps = {
248	  label: string;
249	  className?: string;
250	  message?: string;
251	  canRetry?: boolean;
252	};
253	
254	type LoadingProps = {
255	  className?: string;
256	};
257	
258	type LoadingBoxProps = {
259	  className?: string;
260	  message?: string;
261	};
262	
263	type EmptyBoxProps = {
264	  label?: string;
265	};
266	
267	type MsgBoxProps = {
268	  title?: string;
269	  detail?: React.ReactNode;
270	  className?: string;
271	};
272	
273	type AccessDeniedProps = {
274	  message?: string;
275	};
276	
277	type DataProps = {
278	  NoDataEmptyMsg?: React.ComponentType;
279	  EmptyMsg?: React.ComponentType;
280	  label?: string;
281	  unfilteredData?: any;
282	  data?: any;
283	  children?: React.ReactNode;
284	};
285	
286	type StatusBoxProps = {
287	  label?: string;
288	  loadError?: any;
289	  loaded?: boolean;
290	  data?: any;
291	  skeleton?: React.ReactNode;
292	  unfilteredData?: any;
293	  children?: React.ReactNode;
294	};

